-- Validate plugin code for dangerous patterns before compilation
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > MAX_PLUGIN_SIZE then
        return false, "Plugin code exceeds maximum size of " .. MAX_PLUGIN_SIZE .. " bytes"
    end

    if #code == 0 then
        return false, "Plugin code is empty"
    end

    -- Deny dangerous patterns
    local dangerous_patterns = {
        { pattern = "load%s*%(", desc = "load() calls" },
        { pattern = "loadstring%s*%(", desc = "loadstring() calls" },
        { pattern = "loadfile%s*%(", desc = "loadfile() calls" },
        { pattern = "dofile%s*%(", desc = "dofile() calls" },
        { pattern = "rawget%s*%(", desc = "rawget() calls" },
        { pattern = "rawset%s*%(", desc = "rawset() calls" },
        { pattern = "rawequal%s*%(", desc = "rawequal() calls" },
        { pattern = "setmetatable%s*%(", desc = "setmetatable() calls" },
        { pattern = "getmetatable%s*%(", desc = "getmetatable() calls" },
        { pattern = "setfenv%s*%(", desc = "setfenv() calls" },
        { pattern = "getfenv%s*%(", desc = "getfenv() calls" },
        { pattern = "require%s*%(", desc = "require() calls" },
        { pattern = "module%s*%(", desc = "module() calls" },
        { pattern = "os%.", desc = "os library access" },
        { pattern = "io%.", desc = "io library access" },
        { pattern = "debug%.", desc = "debug library access" },
        { pattern = "package%.", desc = "package library access" },
        { pattern = "coroutine%.", desc = "coroutine library access" },
        { pattern = "_G", desc = "_G access" },
        { pattern = "_ENV", desc = "_ENV access" },
        { pattern = "collectgarbage", desc = "collectgarbage() calls" },
        { pattern = "newproxy", desc = "newproxy() calls" },
        { pattern = "jit%.", desc = "jit library access" },
        { pattern = "ffi%.", desc = "ffi library access" },
        { pattern = "require%s*%(?['\"]ffi", desc = "FFI require" },
        { pattern = "\\27", desc = "bytecode injection" },
    }

    for _, dp in ipairs(dangerous_patterns) do
        if ngx.re.find(code, dp.pattern, "ijo") then
            return false, "Plugin code contains forbidden pattern: " .. dp.desc
        end
    end

    -- Check for bytecode (binary chunks start with \27Lua or \27LJ)
    if string.byte(code, 1) == 27 then
        return false, "Bytecode loading is not permitted"
    end

    return true, nil
end

-- Compute HMAC-SHA256 signature for plugin code integrity verification
local function compute_signature(plugin_name, code)
    local resty_hmac = require "resty.hmac"
    local resty_str = require "resty.string"

    local hmac_sha256 = resty_hmac:new(HMAC_SECRET, resty_hmac.ALGOS.SHA256)
    if not hmac_sha256 then
        return nil, "Failed to create HMAC instance"
    end

    local message = plugin_name .. ":" .. code
    local ok = hmac_sha256:update(message)
    if not ok then
        return nil, "Failed to update HMAC"
    end

    local digest = hmac_sha256:final()
    return resty_str.to_hex(digest), nil
end

-- Verify plugin signature
local function verify_signature(plugin_name, code, provided_signature)
    if not provided_signature or #provided_signature == 0 then
        return false, "No signature provided"
    end

    local expected_sig, err = compute_signature(plugin_name, code)
    if not expected_sig then
        return false, "Failed to compute signature: " .. (err or "unknown")
    end

    -- Constant-time comparison to prevent timing attacks
    if #expected_sig ~= #provided_signature then
        return false, "Invalid signature"
    end

    local result = 0
    for i = 1, #expected_sig do
        result = bit.bor(result, bit.bxor(string.byte(expected_sig, i), string.byte(provided_signature, i)))
    end

    if result ~= 0 then
        return false, "Invalid signature"
    end

    return true, nil
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    if not plugin_name or type(plugin_name) ~= "string" then
        return nil, nil, "Invalid plugin name"
    end

    -- Sanitize plugin name: only allow alphanumeric, hyphens, underscores
    if not ngx.re.find(plugin_name, "^[a-zA-Z0-9_-]+$", "jo") then
        return nil, nil, "Plugin name contains invalid characters"
    end

    if #plugin_name > 128 then
        return nil, nil, "Plugin name too long"
    end

    local red = redis:new()
    red:set_timeout(2000) -- 2 second timeout

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, nil, "Redis connection failed: " .. (err or "unknown")
    end

    if REDIS_PASSWORD and #REDIS_PASSWORD > 0 then
        local auth_ok, auth_err = red:auth(REDIS_PASSWORD)
        if not auth_ok then
            red:close()
            return nil, nil, "Redis auth failed: " .. (auth_err or "unknown")
        end
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local res, redis_err = red:hmget(key, "code", "signature", "enabled", "version")
    if not res or res == ngx.null then
        red:set_keepalive(10000, 100)
        return nil, nil, "Plugin not found in Redis: " .. plugin_name
    end

    local code = res[1]
    local signature = res[2]
    local enabled = res[3]
    local version = res[4]

    -- Return connection to pool
    red:set_keepalive(10000, 100)

    if not code or code == ngx.null then
        return nil, nil, "Plugin code is empty"
    end

    if enabled == ngx.null or enabled ~= "true" then
        return nil, nil, "Plugin is disabled: " .. plugin_name
    end

    if not signature or signature == ngx.null then
        return nil, nil, "Plugin has no signature"
    end

    return code, signature, nil
end

-- Compile and cache plugin with sandboxing
local function compile_plugin(plugin_name, code)
    -- Validate code safety
    local valid, validation_err = validate_plugin_code(code)
    if not valid then
        return nil, "Code validation failed: " .. validation_err
    end

    -- Wrap plugin code to return a function/table
    -- Plugins should return a table with an execute() method
    local wrapped_code = code

    -- Compile the code
    local chunk, compile_err = loadstring(wrapped_code, "=plugin:" .. plugin_name)
    if not chunk then
        return nil, "Compilation failed: " .. (compile_err or "unknown")
    end

    -- Apply sandbox environment
    local sandbox_env = build_sandbox_env()
    setfenv(chunk, sandbox_env)

    return chunk, nil
end

-- Execute a compiled plugin safely
local function execute_plugin(compiled_chunk, plugin_name, request_context)
    -- Build fresh sandbox for this execution
    local sandbox_env = build_sandbox_env(request_context)
    setfenv(compiled_chunk, sandbox_env)

    -- Execute with pcall for error containment
    local exec_ok, plugin_result = pcall(compiled_chunk)
    if not exec_ok then
        return nil, "Plugin execution error: " .. tostring(plugin_result)
    end

    -- Plugin should return a table with an execute() function
    if type(plugin_result) ~= "table" then
        return nil, "Plugin must return a table with an execute() method"
    end

    if type(plugin_result.execute) ~= "function" then
        return nil, "Plugin table must have an execute() function"
    end

    -- Set sandbox on the execute function as well
    setfenv(plugin_result.execute, sandbox_env)

    -- Call the plugin's execute method
    local run_ok, run_result, run_err = pcall(plugin_result.execute, request_context)
    if not run_ok then
        return nil, "Plugin execute() error: " .. tostring(run_result)
    end

    return run_result, run_err
end

-- Get plugin from cache or compile fresh
local function get_or_compile_plugin(plugin_name, code, signature)
    local cache_key = plugin_name .. ":" .. ngx.md5(code)

    -- We cannot cache compiled functions in shared dict, so we use per-worker caching
    -- via module-level table
    if not _M then
        _M = {}
    end
    if not _M.compiled_cache then
        _M.compiled_cache = {}
    end

    -- Check per-worker cache
    local cached = _M.compiled_cache[cache_key]
    if cached then
        return cached, nil
    end

    -- Compile
    local chunk, err = compile_plugin(plugin_name, code)
    if not chunk then
        return nil, err
    end

    -- Cache compiled chunk (limit cache size)
    local cache_count = 0
    for _ in pairs(_M.compiled_cache) do
        cache_count = cache_count + 1
    end
    if cache_count > 1000 then
        -- Evict all (simple strategy; could use LRU)
        _M.compiled_cache = {}
    end
    _M.compiled_cache[cache_key] = chunk

    return chunk, nil
end

-- Rate limiting for plugin loading (per client IP)
local function check_rate_limit()
    local rate_limit_dict = ngx.shared.plugin_rate_limit
    if not rate_limit_dict then
        -- If shared dict not configured, allow but log warning
        ngx.log(ngx.WARN, "plugin_rate_limit shared dict not configured")
        return true
    end

    local client_ip = ngx.var.remote_addr
    local key = "plugin_load:" .. client_ip
    local count, err = rate_limit_dict:incr(key, 1, 0, 60) -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "Rate limit incr failed: ", err)
        return true -- fail open but log
    end

    if count > 30 then -- max 30 plugin loads per minute per IP
        return false
    end

    return true
end

-- Audit logging
local function audit_log(plugin_name, source, client_ip, success, message)
    local log_entry = cjson.encode({
        timestamp = ngx.now(),
        plugin = plugin_name,
        source = source,
        client_ip = client_ip,
        success = success,
        message = message,
    })
    ngx.log(ngx.INFO, "[PLUGIN_AUDIT] ", log_entry)
end

-- Main handler
local function handle_request()
    local client_ip = ngx.var.remote_addr

    -- Rate limit check
    if not check_rate_limit() then
        ngx.status = 429
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Rate limit exceeded for plugin loading" }))
        return ngx.exit(429)
    end

    -- Determine plugin source: Redis (by name) or HTTP header (inline)
    local plugin_name = ngx.var.arg_plugin or ngx.req.get_headers()["X-Plugin-Name"]
    local plugin_source = "unknown"
    local plugin_code, plugin_signature, load_err

    if plugin_name then
        -- Sanitize
        if not ngx.re.find(plugin_name, "^[a-zA-Z0-9_-]+$", "jo") then
            ngx.status = 400
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({ error = "Invalid plugin name format" }))
            audit_log(plugin_name or "unknown", "invalid", client_ip, false, "Invalid plugin name format")
            return ngx.exit(400)
        end

        plugin_source = "redis"
        plugin_code, plugin_signature, load_err = load_plugin_from_redis(plugin_name)

        if not plugin_code then
            ngx.status = 404
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({ error = "Plugin load failed", detail = load_err }))
            audit_log(plugin_name, plugin_source, client_ip, false, load_err)
            return ngx.exit(404)
        end
    else
        -- Inline plugin from header (for development/testing - should be disabled in production)
        local allow_inline = os.getenv("ALLOW_INLINE_PLUGINS")
        if allow_inline ~= "true" then
            ngx.status = 403
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({ error = "Inline plugins are disabled" }))
            audit_log("inline", "header", client_ip, false, "Inline plugins disabled")
            return ngx.exit(403)
        end

        plugin_code = ngx.req.get_headers()["X-Plugin-Code"]
        plugin_signature = ngx.req.get_headers()["X-Plugin-Signature"]
        plugin_name = ngx.req.get_headers()["X-Plugin-Name"] or "inline-" .. ngx.md5(plugin_code or ""):sub(1, 8)
        plugin_source = "header"

        if not plugin_code then
            ngx.status = 400
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({ error = "No plugin specified" }))
            return ngx.exit(400)
        end

        -- Decode base64 if needed
        local decoded = ngx.decode_base64(plugin_code)
        if decoded then
            plugin_code = decoded
        end
    end

    -- Verify signature (mandatory for all sources)
    local sig_valid, sig_err = verify_signature(plugin_name, plugin_code, plugin_signature)
    if not sig_valid then
        ngx.status = 403
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Plugin signature verification failed", detail = sig_err }))
        audit_log(plugin_name, plugin_source, client_ip, false, "Signature verification failed: " .. (sig_err or ""))
        return ngx.exit(403)
    end

    -- Compile plugin
    local compiled_chunk, compile_err = get_or_compile_plugin(plugin_name, plugin_code, plugin_signature)
    if not compiled_chunk then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Plugin compilation failed", detail = compile_err }))
        audit_log(plugin_name, plugin_source, client_ip, false, "Compilation failed: " .. (compile_err or ""))
        return ngx.exit(400)
    end

    -- Build request context for the plugin
    local request_context = {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = ngx.req.get_uri_args(50),
        headers = (function()
            local h = ngx.req.get_headers(50)
            -- Strip sensitive headers from context
            h["authorization"] = nil
            h["cookie"] = nil
            h["x-plugin-code"] = nil
            h["x-plugin-signature"] = nil
            return h
        end)(),
        client_ip = client_ip,
        plugin_name = plugin_name,
    }

    -- Read body if present
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if body and #body <= 65536 then -- limit body size passed to plugin
        request_context.body = body
        -- Try to parse JSON body
        local json_body = cjson.decode(body)
        if json_body then
            request_context.json_body = json_body
        end
    end

    -- Execute plugin
    local result, exec_err = execute_plugin(compiled_chunk, plugin_name, request_context)
    if exec_err then
        ngx.status = 500
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Plugin execution failed", detail = exec_err }))
        audit_log(plugin_name, plugin_source, client_ip, false, "Execution failed: " .. (exec_err or ""))
        return ngx.exit(500)
    end

    -- Audit success
    audit_log(plugin_name, plugin_source, client_ip, true, "Plugin executed successfully")

    -- Return result
    ngx.status = 200
    ngx.header["Content-Type"] = "application/json"
    ngx.header["X-Plugin-Name"] = plugin_name
    ngx.say(cjson.encode({
        success = true,
        plugin = plugin_name,
        result = result,
    }))
end

-- Admin endpoint: register a plugin in Redis with proper signing
local function handle_admin_register()
    -- Only allow from trusted IPs
    local client_ip = ngx.var.remote_addr
    local trusted_ips = { ["127.0.0.1"] = true, ["::1"] = true }

    -- Check for additional trusted IPs from env
    local extra_ips = os.getenv("TRUSTED_ADMIN_IPS")
    if extra_ips then
        for ip in string.gmatch(extra_ips, "[^,]+") do
            trusted_ips[ip:match("^%s*(.-)%s*$")] = true
        end
    end

    if not trusted_ips[client_ip] then
        ngx.status = 403
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Access denied" }))
        audit_log("admin", "register", client_ip, false, "Untrusted IP")
        return ngx.exit(403)
    end

    -- Verify admin API key
    local admin_key = ngx.req.get_headers()["X-Admin-Key"]
    local expected_key = os.getenv("ADMIN_API_KEY")
    if not expected_key or not admin_key or admin_key ~= expected_key then
        ngx.status = 401
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Invalid admin credentials" }))
        audit_log("admin", "register", client_ip, false, "Invalid admin key")
        return ngx.exit(401)
    end

