    local body = ngx.req.get_body_data()
    if not body then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Request body required" }))
        return ngx.exit(400)
    end

    local data = cjson.decode(body)
    if not data or not data.name or not data.code then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "name and code fields required" }))
