    if not ngx.re.find(plugin_name, "^[a-zA-Z0-9_-]+$", "jo") or #plugin_name > 128 then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Invalid plugin name" }))
        return ngx.exit(400)
    end

    -- Validate code
    local valid, validation_err = validate_plugin_code(plugin_code)
    if not valid then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Code validation failed", detail = validation_err }))
        return ngx.exit(400)
    end

    -- Test compilation
    local test_chunk, compile_err = compile_plugin(plugin_name, plugin_code)
    if not test_chunk then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Code compilation failed", detail = compile_err }))
        return ngx.exit(400)
    end

    -- Generate signature
    local signature, sig_err = compute_signature(plugin_name, plugin_code)
    if not signature then
        ngx.status = 500
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Failed to generate signature", detail = sig_err }))
        return ngx.exit(500)
    end

    -- Store in Redis
    local red = redis:new()
    red:set_timeout(2000)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.status = 500
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Redis connection failed" }))
        return ngx.exit(500)
    end

    if REDIS_PASSWORD and #REDIS_PASSWORD > 0 then
        red:auth(REDIS_PASSWORD)
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local version = tostring(ngx.now())

    red:init_pipeline()
    red:hmset(key,
        "code", plugin_code,
        "signature", signature,
        "enabled", enabled,
        "version", version,
        "registered_by", client_ip,
        "registered_at", ngx.now()
    )
    local results, pipeline_err = red:commit_pipeline()
    red:set_keepalive(10000, 100)

    if not results then
        ngx.status = 500
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Failed to store plugin" }))
        audit_log(plugin_name, "register", client_ip, false, "Redis store failed")
        return ngx.exit(500)
    end

    audit_log(plugin_name, "register", client_ip, true, "Plugin registered successfully")

    ngx.status = 201
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode({
        success = true,
        plugin = plugin_name,
        version = version,
        signature = signature,
    }))
end

-- Router
local uri = ngx.var.uri

if uri == "/gateway/plugin/execute" then
    handle_request()
elseif uri == "/gateway/plugin/register" then
    if ngx.req.get_method() == "POST" then
        handle_admin_register()
    else
        ngx.status = 405
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({ error = "Method not allowed" }))
        ngx.exit(405)
    end
elseif uri == "/gateway/plugin/health" then
    ngx.status = 200
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode({ status = "ok", timestamp = ngx.now() }))
else
    ngx.status = 404
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode({ error = "Not found" }))
    ngx.exit(404)
end